package com.example.webviewwrapper

import android.Manifest
import android.app.Activity
import android.content.Context
import android.content.SharedPreferences
import android.content.pm.PackageManager
import android.os.Build
import android.util.Log
import android.webkit.JavascriptInterface
import android.webkit.WebView
import android.widget.Toast
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import org.json.JSONObject
import java.lang.ref.WeakReference

class NativeBridge(
    private val activityRef: WeakReference<Activity>,
    private val webViewRef: WeakReference<WebView>
) {
    companion object {
        const val BRIDGE_NAME = "NativeBridge"
        const val TAG = "NativeBridge"
        const val PREFS_NAME = "WebAppLocalStorage"
        const val CAMERA_PERMISSION_REQUEST = 1001
        const val NOTIFICATION_PERMISSION_REQUEST = 1002
    }

    private val prefs: SharedPreferences?
        get() = activityRef.get()?.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    // ==================== Camera Access ====================

    @JavascriptInterface
    fun requestCameraPermission(): String {
        val activity = activityRef.get() ?: return createErrorResponse("Activity not available")

        return if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA)
            == PackageManager.PERMISSION_GRANTED
        ) {
            createSuccessResponse("Camera permission already granted")
        } else {
            activity.runOnUiThread {
                ActivityCompat.requestPermissions(
                    activity,
                    arrayOf(Manifest.permission.CAMERA),
                    CAMERA_PERMISSION_REQUEST
                )
            }
            createResponse("pending", "Camera permission requested")
        }
    }

    @JavascriptInterface
    fun hasCameraPermission(): Boolean {
        val activity = activityRef.get() ?: return false
        return ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) ==
                PackageManager.PERMISSION_GRANTED
    }

    @JavascriptInterface
    fun openCamera() {
        val activity = activityRef.get() ?: return
        if (activity is MainActivity) {
            activity.runOnUiThread {
                activity.launchCamera()
            }
        }
    }

    @JavascriptInterface
    fun capturePhoto(callbackName: String) {
        val activity = activityRef.get() ?: return
        if (activity is MainActivity) {
            activity.runOnUiThread {
                activity.capturePhoto(callbackName)
            }
        }
    }

    // ==================== Local Storage ====================

    @JavascriptInterface
    fun setItem(key: String, value: String): Boolean {
        return try {
            prefs?.edit()?.putString(key, value)?.apply()
            Log.d(TAG, "Stored: $key")
            true
        } catch (e: Exception) {
            Log.e(TAG, "Error storing item: ${e.message}")
            false
        }
    }

    @JavascriptInterface
    fun getItem(key: String): String? {
        return try {
            prefs?.getString(key, null)
        } catch (e: Exception) {
            Log.e(TAG, "Error getting item: ${e.message}")
            null
        }
    }

    @JavascriptInterface
    fun removeItem(key: String): Boolean {
        return try {
            prefs?.edit()?.remove(key)?.apply()
            true
        } catch (e: Exception) {
            Log.e(TAG, "Error removing item: ${e.message}")
            false
        }
    }

    @JavascriptInterface
    fun clear(): Boolean {
        return try {
            prefs?.edit()?.clear()?.apply()
            true
        } catch (e: Exception) {
            Log.e(TAG, "Error clearing storage: ${e.message}")
            false
        }
    }

    @JavascriptInterface
    fun getAllKeys(): String {
        return try {
            val keys = prefs?.all?.keys ?: emptySet()
            JSONObject().apply {
                put("keys", org.json.JSONArray(keys.toList()))
            }.toString()
        } catch (e: Exception) {
            Log.e(TAG, "Error getting keys: ${e.message}")
            "[]"
        }
    }

    @JavascriptInterface
    fun getStorageSize(): Int {
        return prefs?.all?.size ?: 0
    }

    // ==================== Push Notifications ====================

    @JavascriptInterface
    fun requestNotificationPermission(): String {
        val activity = activityRef.get() ?: return createErrorResponse("Activity not available")

        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(
                    activity,
                    Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED
            ) {
                createSuccessResponse("Notification permission already granted")
            } else {
                activity.runOnUiThread {
                    ActivityCompat.requestPermissions(
                        activity,
                        arrayOf(Manifest.permission.POST_NOTIFICATIONS),
                        NOTIFICATION_PERMISSION_REQUEST
                    )
                }
                createResponse("pending", "Notification permission requested")
            }
        } else {
            createSuccessResponse("Notification permission not required for this Android version")
        }
    }

    @JavascriptInterface
    fun hasNotificationPermission(): Boolean {
        val activity = activityRef.get() ?: return false
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            ContextCompat.checkSelfPermission(
                activity,
                Manifest.permission.POST_NOTIFICATIONS
            ) == PackageManager.PERMISSION_GRANTED
        } else {
            true
        }
    }

    @JavascriptInterface
    fun getPushToken(): String {
        val token = prefs?.getString("fcm_token", null)
        return token ?: ""
    }

    @JavascriptInterface
    fun subscribeToPushTopic(topic: String): Boolean {
        return try {
            com.google.firebase.messaging.FirebaseMessaging.getInstance()
                .subscribeToTopic(topic)
            Log.d(TAG, "Subscribed to topic: $topic")
            true
        } catch (e: Exception) {
            Log.e(TAG, "Error subscribing to topic: ${e.message}")
            false
        }
    }

    @JavascriptInterface
    fun unsubscribeFromPushTopic(topic: String): Boolean {
        return try {
            com.google.firebase.messaging.FirebaseMessaging.getInstance()
                .unsubscribeFromTopic(topic)
            Log.d(TAG, "Unsubscribed from topic: $topic")
            true
        } catch (e: Exception) {
            Log.e(TAG, "Error unsubscribing from topic: ${e.message}")
            false
        }
    }

    // ==================== Utility Functions ====================

    @JavascriptInterface
    fun showToast(message: String) {
        val activity = activityRef.get() ?: return
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun getDeviceInfo(): String {
        return JSONObject().apply {
            put("manufacturer", Build.MANUFACTURER)
            put("model", Build.MODEL)
            put("sdkVersion", Build.VERSION.SDK_INT)
            put("release", Build.VERSION.RELEASE)
            put("platform", "android")
        }.toString()
    }

    @JavascriptInterface
    fun getPlatform(): String = "android"

    @JavascriptInterface
    fun getAppVersion(): String {
        val activity = activityRef.get() ?: return "unknown"
        return try {
            val pInfo = activity.packageManager.getPackageInfo(activity.packageName, 0)
            pInfo.versionName ?: "unknown"
        } catch (e: Exception) {
            "unknown"
        }
    }

    // Execute JavaScript callback on the WebView
    fun executeCallback(callbackName: String, data: String) {
        val webView = webViewRef.get() ?: return
        val activity = activityRef.get() ?: return
        activity.runOnUiThread {
            webView.evaluateJavascript(
                "javascript:if(typeof $callbackName === 'function') { $callbackName($data); }",
                null
            )
        }
    }

    fun notifyPermissionResult(permission: String, granted: Boolean) {
        val webView = webViewRef.get() ?: return
        val activity = activityRef.get() ?: return
        val json = JSONObject().apply {
            put("permission", permission)
            put("granted", granted)
        }.toString()
        activity.runOnUiThread {
            webView.evaluateJavascript(
                "javascript:if(typeof onNativePermissionResult === 'function') { onNativePermissionResult($json); }",
                null
            )
        }
    }

    private fun createSuccessResponse(message: String): String {
        return JSONObject().apply {
            put("status", "success")
            put("message", message)
        }.toString()
    }

    private fun createErrorResponse(message: String): String {
        return JSONObject().apply {
            put("status", "error")
            put("message", message)
        }.toString()
    }

    private fun createResponse(status: String, message: String): String {
        return JSONObject().apply {
            put("status", status)
            put("message", message)
        }.toString()
    }
}

