class MainActivity : AppCompatActivity() {

    companion object {
        const val TAG = "WebViewWrapper"
        const val WEB_APP_URL = "https://your-web-app-url.com" // Replace with your web app URL
    }

    private lateinit var webView: WebView
    private lateinit var progressBar: ProgressBar
    private lateinit var nativeBridge: NativeBridge

    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null
    private var cameraPhotoPath: String? = null
    private var pendingCameraCallback: String? = null

    private lateinit var fileChooserLauncher: ActivityResultLauncher<Intent>
    private lateinit var cameraLauncher: ActivityResultLauncher<Uri>
    private var cameraImageUri: Uri? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        webView = findViewById(R.id.webView)
        progressBar = findViewById(R.id.progressBar)

        setupActivityResultLaunchers()
        setupWebView()
        setupBridge()

        // Load the web app
        webView.loadUrl(WEB_APP_URL)

        // Initialize FCM token
        initializeFCM()
    }

    private fun setupActivityResultLaunchers() {
        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                val data = result.data
                val results: Array<Uri>? = if (data?.data != null) {
                    arrayOf(data.data!!)
                } else if (cameraPhotoPath != null) {
                    val uri = Uri.parse(cameraPhotoPath)
                    arrayOf(uri)
                } else {
                    null
                }
                fileUploadCallback?.onReceiveValue(results)
            } else {
                fileUploadCallback?.onReceiveValue(null)
            }
            fileUploadCallback = null
        }

        cameraLauncher = registerForActivityResult(
            ActivityResultContracts.TakePicture()
        ) { success ->
            if (success && cameraImageUri != null) {
                val callback = pendingCameraCallback
                if (callback != null) {
                    val json = org.json.JSONObject().apply {
                        put("success", true)
                        put("uri", cameraImageUri.toString())
                    }.toString()
                    nativeBridge.executeCallback(callback, json)
                }
                Toast.makeText(this, "Photo captured successfully", Toast.LENGTH_SHORT).show()
            } else {
                val callback = pendingCameraCallback
                if (callback != null) {
                    val json = org.json.JSONObject().apply {
                        put("success", false)
                        put("error", "Photo capture cancelled or failed")
                    }.toString()
                    nativeBridge.executeCallback(callback, json)
                }
            }
            pendingCameraCallback = null
        }
    }

